INSERT INTO `evento` VALUES (15,_binary '','Yung Beef acudirá a Jaén para actuar musicalmente en su gira de el dia de la bestia, trayendo sonidos nuevos a la escena.','2026-05-21 21:00:00.000000','uploads/eventos/35fa4513-c109-4365-8c8d-37b4cf8180cd.jpg','Yung Beef Tour',14,2),(16,_binary '','Los artistas locales Xiyo y Fernandezz daran un espectaculo en el Olivo Arena para consagrarse como los artista underground del momento','2026-05-25 22:15:00.000000','uploads/eventos/28d8c316-0b78-4dcb-840d-54a9a807d749.jfif','Xiyo y Fernandezz',14,2),(17,_binary '','El Futbol Club Barcelona y el Jaén Paraíso Interior se verán las caras para decidir quien será el campeón de la Copa de España de futbol sala ','2026-03-22 21:00:00.000000','uploads/eventos/1af6a6ae-da16-4043-b817-348a73686bb6.jfif','Final Copa España Futbol Sala',13,1),(18,_binary '','La artista, que se inserta en el panorama musical con una voz prometedora y un estilo muy auténtico, inicia su gira en la capital jiennense. Los andaluces acogerán el evento con una especial ilusión. ','2026-10-26 21:30:00.000000','uploads/eventos/df61d57e-1d1a-4ae5-a8c0-737e43d3fd04.jfif','Judeline Tour 2026',14,2);
